const texto = $input.item.json.output || "";

// ── INTENTO 1: parsear el bloque JSON estructurado (fuente de verdad) ──────────
try {
  const m = texto.match(/<<<JSON>>>([\s\S]*?)<<<FINJSON>>>/);
  if (m) {
    const data = JSON.parse(m[1].trim());
    return [{
      json: {
        id:               data.id ?? "No encontrado",
        nombre:           data.nombre ?? "N/D",
        fecha_entrevista: data.fecha_entrevista ?? "N/D",
        hora_entrevista:  data.hora_entrevista ?? "N/D",
        entrevistador:    data.entrevistador ?? "N/D",
        es_programador:   data.es_programador ?? "N/D",
        no_actualizar:    data.no_actualizar === true,
        texto_completo:   texto
      }
    }];
  }
} catch (e) {
  // Si el JSON viene malformado, seguimos al fallback de regex.
}

// ── INTENTO 2 (FALLBACK): regex sobre el texto, como antes ────────────────────
// (la variable 'texto' ya está declarada arriba)

// ── Helper base ───────────────────────────────────────────────────────────────
const get = (pattern) => {
  const m = texto.match(pattern);
  return m ? m[1].trim() : "N/D";
};

// ── Detección: ¿es mensaje de "no programador"? ───────────────────────────────
const noProgMatch = texto.match(
  /El candidato\s+([^\n]+?)\s+no es programador\.\s+No se realizará ninguna actualización/i
);
if (noProgMatch) {
  return [{
    json: {
      id:               "N/D",
      nombre:           noProgMatch[1].trim(),
      fecha_entrevista: "N/D",
      hora_entrevista:  "N/D",
      entrevistador:    "N/D",
      es_programador:   "No",
      no_actualizar:    true,
      texto_completo:   texto
    }
  }];
}

// ── Buscar línea de confirmación (con o sin markdown) ─────────────────────────
// Acepta tanto: "Datos extraídos para Juan García con ID: 20"
// como variantes con asteriscos: "Datos extraídos para **Juan García** con ID: **20**"
const confirmLine = texto.match(
  /Datos extraídos para\s+\*{0,2}([^*\n]+?)\*{0,2}\s+con ID:\s*\*{0,2}(\d+)\*{0,2}/i
);

// ── ID ────────────────────────────────────────────────────────────────────────
const id = (() => {
  if (confirmLine) return parseInt(confirmLine[2]);
  // Fallback: cualquier mención de ID seguida de número
  const m = texto.match(/\bID[:\s#]+\*{0,2}(\d+)\*{0,2}/i);
  return m ? parseInt(m[1]) : "No encontrado";
})();

// ── Nombre ────────────────────────────────────────────────────────────────────
const nombre = (() => {
  if (confirmLine) return confirmLine[1].trim();
  // Fallback: busca "candidato **Nombre**" o "para **Nombre**"
  const m = texto.match(/(?:candidato|para)\s+\*{0,2}([A-ZÁÉÍÓÚÑ][^*\n,]{3,50}?)\*{0,2}(?:\s+(?:con|ha|no))/i);
  return m ? m[1].trim() : "N/D";
})();

// ── Fecha ─────────────────────────────────────────────────────────────────────
const fecha = (() => {
  // Primero busca en la línea de confirmación exacta
  const m1 = texto.match(/Entrevista asignada el\s+\*{0,2}(\d{4}-\d{2}-\d{2})\*{0,2}/i);
  if (m1) return m1[1];
  // Fallback: cualquier fecha en formato YYYY-MM-DD
  const m2 = texto.match(/\b(\d{4}-\d{2}-\d{2})\b/);
  return m2 ? m2[1] : "N/D";
})();

// ── Hora ──────────────────────────────────────────────────────────────────────
const hora = (() => {
  const m1 = texto.match(/a las\s+\*{0,2}(\d{2}:\d{2})\*{0,2}/i);
  if (m1) return m1[1];
  // Fallback: hora suelta
  const m2 = texto.match(/\b(0[9-9]|1[0-2]):[0-5]\d\b/);
  return m2 ? m2[0] : "N/D";
})();

// ── Entrevistador ─────────────────────────────────────────────────────────────
const entrevistador = (() => {
  // Lista fija de entrevistadores válidos
  const nombres = ["Fabrizio Castillo", "Joaquín Luna", "Manuel Palmero", "Uriel Rojas"];
  // Busca en la línea de confirmación primero
  const m1 = texto.match(/con\s+\*{0,2}(Fabrizio Castillo|Joaqu[ií]n Luna|Manuel Palmero|Uriel Rojas)\*{0,2}[\.\s]/i);
  if (m1) {
    // Normaliza "Joaquin" → "Joaquín"
    return nombres.find(n => n.toLowerCase().replace("í","i") === m1[1].toLowerCase().replace("í","i")) || m1[1];
  }
  // Fallback: busca cualquier mención del nombre en el texto
  for (const n of nombres) {
    if (texto.includes(n)) return n;
  }
  return "N/D";
})();

// ── ¿Es programador? ──────────────────────────────────────────────────────────
const esProgramador = (() => {
  // Formato exacto esperado: "¿Es programador?: Sí"
  const m1 = texto.match(/[¿?]?Es\s+programador\?[:\s*]+\*{0,2}(Sí|Si|No|N\/D)\*{0,2}/i);
  if (m1) {
    const v = m1[1].toLowerCase();
    return (v === "sí" || v === "si") ? "Sí" : v === "no" ? "No" : "N/D";
  }
  // Fallback: detección por frases comunes del agente
  if (/(?:sí es programador|es\s+un\s+programador|perfil\s+(?:es\s+)?técnico)/i.test(texto)) return "Sí";
  if (/no es programador|perfil\s+no\s+técnico/i.test(texto)) return "No";
  return "N/D";
})();

return [{
  json: {
    id,
    nombre,
    fecha_entrevista: fecha,
    hora_entrevista:  hora,
    entrevistador,
    es_programador:   esProgramador,
    no_actualizar:    false,
    texto_completo:   texto
  }
}];

const text = $input.first().json.text || '';  // El texto que extrajo el nodo anterior

// Limpia espacios y saltos de línea
const cleanText = text.trim().replace(/\s+/g, ' ');

if (cleanText.length > 100) {  // Ajusta el umbral según tus PDFs (50-100 caracteres suele ser bueno)
    return [{ json: { isScanned: false, text: cleanText, confidence: 'high' } }];
} else {
    return [{ json: { isScanned: true, text: '', confidence: 'high' } }];
}
